// ============================================
// NORMALIZACIÓN A SMARCOS EVENT SCHEMA v1
// ============================================

const input = $input.item.json;
const timestamp = new Date().toISOString();

// Determinar fuente
let sourceBox = 'UNKNOWN';
let territory = 'CL-UNKNOWN';
let entityType = 'Lead';
let action = 'unknown';
let intent = 'general_inquiry';
let trustScore = 0.5;

// Chatwoot webhook
if (input.message_type === 'incoming' || input.source === 'chatwoot') {
  sourceBox = 'CHATWOOT-001';
  territory = input.conversation?.metadata?.territory || 'CL-RM';
  entityType = 'Message';
  action = 'customer_inquiry';
  intent = input.content?.includes('precio') ? 'pricing_request' : 'general_inquiry';
  trustScore = 0.85;
}

// Google Maps scraper
else if (input.source === 'maps_scraper' || input.google_maps_url) {
  sourceBox = 'SCRAPER-001';
  territory = 'CL-RM-CENTRO';
  entityType = 'Lead';
  action = 'lead_discovered';
  intent = 'general_inquiry';
  trustScore = 0.70;
}

// Odoo event
else if (input.source === 'odoo' || input.model) {
  sourceBox = 'ODOO-CORE';
  territory = 'CL-RM';
  entityType = input.model || 'Partner';
  action = input.event_type || 'record_updated';
  intent = input.intent || 'general_inquiry';
  trustScore = 0.95;
}

// Mailgun webhook
else if (input.event === 'clicked' || input.source === 'mailgun') {
  sourceBox = 'MAILGUN-001';
  territory = 'CL-BIO';
  entityType = 'Message';
  action = 'email_reply';
  intent = 'support';
  trustScore = 0.90;
}

// Picoclaw validación
else if (input.source === 'picoclaw' || input.sms_validated) {
  sourceBox = 'PICOLAW-001';
  territory = 'CL-RM';
  entityType = 'Partner';
  action = 'validated';
  intent = 'purchase_urgent';
  trustScore = 1.0;
}

// Construir evento normalizado
const event = {
  metadata: {
    source_box_id: sourceBox,
    territory: territory,
    protocol: 'MCP-V1',
    correlation_id: `evt_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
  },
  payload: {
    entity: entityType,
    action: action,
    data: {
      intent: intent,
      customer_id: input.customer_id || input.id || null,
      message: input.content || input.message || input.description || null,
      phone: input.phone || input.telefono || null,
      email: input.email || null,
      business_name: input.business_name || input.name || null,
      product: input.product || input.product_id || null,
      // Datos específicos por fuente
      channel: input.channel || null,
      campaign_id: input.campaign_id || null,
      order_id: input.order_id || null,
      amount_total: input.amount_total || null
    }
  },
  trust_score: trustScore,
  timestamp: timestamp,
  lifecycle: 'ingested'
};

return { json: event };
